import csv
import json
import requests

def extract_csv(path):
    data = []
    with open(path, 'r') as f:
        reader = csv.DictReader(f)
        for row in reader:
            data.append(row)
    return data

def extract_json(json_str):
    return json.loads(json_str)

def extract_api(url):
    response = requests.get(url)
    response.raise_for_status()
    return response.json()

