function calculateTotals(purchases) {
  let totals = {};
  for (let i = 0; i < purchases.length; i++) {
    let user = purchases[i].userId;
    let amount = purchases[i].amount;
    if (totals[user] === undefined) {
      totals[user] = 0;
    }
    totals[user] = totals[user] + amount;
  }
  return totals;
}

